/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements the NotificationAdapter interface so it can be registered
 * with the NotificationService. Provides:
 * - JSON payload formatting from NotificationPayload
 * - URL validation before sending
 * - Configurable transport: accepts a WebhookTransport for actual delivery
 *   (defaults to an in-memory store for testing)
 *
 * Architecture: All notifications flow through EventBus → NotificationService
 * → this adapter. Do NOT call send() directly from services.
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a webhook request ready for delivery.
 */
export interface WebhookRequest {
  url: string;
  body: string;
  headers: Record<string, string>;
  sentAt: Date;
}

/**
 * Transport interface for pluggable webhook delivery backends.
 * Implement this to use a real HTTP client (fetch, axios, etc.).
 */
export interface WebhookTransport {
  post(request: WebhookRequest): Promise<{ success: boolean; statusCode?: number; error?: string }>;
}

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookAdapterConfig {
  /** The URL to POST notifications to. */
  url: string;
  /** Optional secret for signing payloads (included as X-Webhook-Secret header). */
  secret?: string;
  /** Optional custom transport. Defaults to in-memory store. */
  transport?: WebhookTransport;
}

/**
 * Validate that a string is a valid HTTP(S) URL.
 */
function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

/**
 * Format a NotificationPayload as a JSON webhook body.
 */
function formatPayload(payload: NotificationPayload): Record<string, unknown> {
  return {
    id: payload.id,
    type: payload.type,
    channel: payload.channel,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    priority: payload.priority,
    createdAt: payload.createdAt.toISOString(),
    metadata: payload.metadata ?? {},
  };
}

/**
 * In-memory webhook transport for testing and development.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private requests: WebhookRequest[] = [];

  async post(request: WebhookRequest): Promise<{ success: boolean; statusCode?: number; error?: string }> {
    this.requests.push(request);
    return { success: true, statusCode: 200 };
  }

  getSentRequests(): WebhookRequest[] {
    return [...this.requests];
  }

  clear(): void {
    this.requests = [];
  }
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;

  private logger = new Logger('WebhookAdapter');
  private config: WebhookAdapterConfig;
  private transport: WebhookTransport;
  private sentRequests: WebhookRequest[] = [];

  constructor(config: WebhookAdapterConfig) {
    if (!isValidUrl(config.url)) {
      throw new Error(`Invalid webhook URL: ${config.url}`);
    }
    this.config = config;
    this.transport = config.transport ?? new InMemoryWebhookTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending webhook to ${this.config.url}: ${payload.subject}`);

    const jsonBody = JSON.stringify(formatPayload(payload));

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };
    if (this.config.secret) {
      headers['X-Webhook-Secret'] = this.config.secret;
    }

    const request: WebhookRequest = {
      url: this.config.url,
      body: jsonBody,
      headers,
      sentAt: new Date(),
    };

    const transportResult = await this.transport.post(request);
    if (!transportResult.success) {
      this.logger.error(`Webhook delivery failed: ${transportResult.error}`);
      return {
        success: false,
        notification: payload,
        deliveredAt: new Date(),
        error: transportResult.error ?? 'Webhook delivery failed',
      };
    }

    this.sentRequests.push(request);

    return {
      success: true,
      notification: payload,
      deliveredAt: request.sentAt,
    };
  }

  /**
   * Get all successfully sent webhook requests. Useful for testing.
   */
  getSentRequests(): WebhookRequest[] {
    return [...this.sentRequests];
  }

  /**
   * Clear sent requests. Useful for testing.
   */
  clearSentRequests(): void {
    this.sentRequests = [];
  }
}

