    transport = new InMemoryWebhookTransport();
  });

  it('should store sent requests', async () => {
    const request: WebhookRequest = {
      url: TEST_URL,
      body: '{"test": true}',
      headers: { 'Content-Type': 'application/json' },
      sentAt: new Date(),
    };
    const result = await transport.post(request);

    expect(result.success).toBe(true);
    expect(result.statusCode).toBe(200);
    expect(transport.getSentRequests()).toHaveLength(1);
    expect(transport.getSentRequests()[0]!.url).toBe(TEST_URL);
  });

  it('should clear requests', async () => {
    await transport.post({
      url: TEST_URL,
      body: '{}',
      headers: {},
      sentAt: new Date(),
    });
    transport.clear();
    expect(transport.getSentRequests()).toHaveLength(0);
  });
});

